DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "niceTables.pl", "contextForm.pl", "contextFraction.pl", "parserPopUp.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("Fraction"); Context()->variables->are(C => 'Real'); $proposed_solution = random(35, 55, 5); $left = Formula("9/5 C + 32"); $right = Formula(118); Context("LimitedNumeric"); $lefteval = Real($left->eval(C => $proposed_solution)); $righteval = Real($right->eval(C => $proposed_solution)); $dropdown = DropDown( ["Yes, it is a solution.", "No, it is not a solution."], ($lefteval >= $righteval) ? 0 : 1, showInStatic => 0 );
############################################################ # Body ############################################################
BEGIN_PGML To kill bedbug eggs using heat, they must be exposed to at least [`118^{\circ}F`] for at least 90 minutes. If you only know the Celsius temperature [`C\text{,}`] then to kill the eggs means we have the inequality [`\frac{9}{5}C+32\geq118\text{.}`] You have some infested blankets that you put in a sauna for 90 minutes, but the sauna temperature is [`[$proposed_solution]^{\circ}C\text{.}`] Was this hot enough to kill the eggs?
>> [@DataTable( [ [PGML('[`[$left->TeX]`]'), PGML('[`\geq`]'), PGML('[`[$right->TeX]`]'), ], [PGML('[_]{$lefteval}{3}'), PGML('[`\wonder{\geq}`]'), PGML('[`[$righteval->TeX]`]'), ], ], align => 'rcl', valign => 'middle',);@]* <<
[_]{$dropdown}{5}
END_PGML
